SELECT * FROM ( SELECT
, (SELECT hm.MEM_NAME FROM HC_MEMBER hm WHERE hm.MEM_ID = le.REG_ID) AS MEM_NAME FROM LEARNING AS le WHERE 1=1 ) le WHERE 1=1 AND le.DELETE_YN != 'Y'
ORDER BY ID ${learnFileUploadDtOrd}

mapper.update:
		UPDATE LEARNING
	    SET 
	    	MOD_ID = #{modId}
	    	, MOD_DT = current_timestamp()
	    	, EPOCH = #{epoch}
	    	, LEARNING_RATE = #{learningRate}
	    	, BATCH_SIZE = #{batchSize}
	    	, ANSWER_FILE_NAME = #{answerFileName}
			, ANSWER_FILE_SAVE_NAME = #{answerFileSaveName}
			, ANSWER_FILE_URL = #{answerFileUrl}
			, ANSWER_FILE_SIZE = #{answerFileSize}
			, ANSWER_FILE_UPLOAD_DT = current_timestamp()
			, ANSWER_STATUS = #{answerStatus}
	    WHERE ID = #{id}
        	AND DELETE_YN != 'Y'

		UPDATE LEARNING
	    SET 
	    	MOD_ID = #{modId}
	    	, MOD_DT = current_timestamp()
			, LEARN_STATUS = #{learnStatus}
